/* Aula 01 — modelJs: seu kit mínimo no Console */

// 1) Testes rápidos
2 + 2;
10 * 3;
'Bruno' + ' Carvalho';

// 2) Comparações
2 > 1;
5 == '5';   // true (converte)
5 === '5';  // false (tipo diferente)

// 3) Seu primeiro "log" (você vai usar sempre)
console.log('Olá, Console!');
console.log('Resultado:', 15 + 27);
